import{_ as i,o as a,c as t,ag as n}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung020.jpg",m=JSON.parse('{"title":"Übung Lektion 12","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung12.md","filePath":"lektionen/uebung12.md"}'),l={name:"lektionen/uebung12.md"};function p(s,e,o,u,h,d){return a(),t("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-12" tabindex="-1">Übung Lektion 12 <a class="header-anchor" href="#ubung-lektion-12" aria-label="Permalink to &quot;Übung Lektion 12&quot;">​</a></h1><p>A) Bilden Sie aus den Aktivsätzen von <a href="./lektion07">Lektion 7</a>, Übung A mit dem PPP Passivsätze der Vergangenheit, bei intransitiven Verben und Verben der Bewegung Aktivsätze der Vergangenheit.</p><p>१. ब्राह्मणेन देव इष्टः । देवीष्टा । विष्णुरिष्टह् । ब्राह्मणेनाग्निरिष्टः । देवतेष्टा ।</p><p>२. गुरुणा फलं खादितम् ।</p><p>३. साधुः स्वर्गं गतः ।</p><p>४. शूद्रा नरकं गता ।</p><p>५. शूद्रो जितः ॥</p><p>B) Bilden Sie die entsprechenden PPPs zu den Verbformen von <a href="./lektion10">Lektion 10</a>, Übung A. Beachten Sie dabei, dass einer Form wie sṛjati PPPs in allen drei Geschlechtern entsprechen.</p><ol><li>sṛjati सृजति सृष्टः । सृष्टा । सृष्टम्</li><li>yudhyate युध्यते युद्धः ३</li><li>bhavanti भवन्ति भूताः । भूताः । भूतानि</li><li>yajati यजति इष्टः ३</li><li>nṛtyati नृत्यति नृत्तः ३</li><li>nayanti नयन्ति नीताः ३</li><li>smarati स्मरति स्मृतः ३</li><li>śṛṇvanti शृण्वन्ति श्रुताः ३</li><li>pāśyati पश्यति (Passiv wird von dṛś gebildet!) दृष्टः ३</li><li>jayanti जयन्ति जिताः ३</li><li>kurvate कुर्वते कृताः ३</li><li>āpnuvanti आप्नुवन्ति आप्ताः ३</li><li>viśati विशति विष्टः ३</li><li>khādanti खादन्ति खादिताः ३</li><li>sunoti सुनोति सुतः ३</li><li>gacchati गच्छति गतः ३</li><li>manyante मन्यन्ते मताः ३</li><li>labhante लभन्ते लब्धाः ३</li><li>rakṣanti रक्षन्ति रक्षिताः ३</li><li>vadanti वदन्ति उदिताः ३</li><li>pṛcchanti पृच्छन्ति पृष्टाः ३</li><li>tanvanti तन्वन्ति तताः ३</li></ol><p>C) Setzen Sie die Sätze von <a href="./lektion10">Lektion 10</a>, Übung C passiv in die Vergangenheit.</p><p>1. brāhmaṇo devīm yajati. ब्राह्मणो देवीं यजति | ब्रामणेन देवीष्टा ।</p><p>2. sādhuḥ svargaṃ gacchati. साधुः स्वर्गं गच्छति | साधुः स्वर्गं गतः ।</p><p>3. śūdraṃ jayati. शूद्रं जयति | शूद्रो जितः ।</p><p>4. guruḥ phalāni khādati. गुरुः फलानि खादति | गुरुणा फलानि खादितानि ।</p><p>5. gurūñchṛṇoti. गुरूञ्छृणोति | ग्रुरवः श्रुताः ।</p><p>6. ko &#39;gniṃ paśyati. को ऽग्निं पश्यति | केनाग्निर्दृष्टः ।</p><p>7. ayaṃ kavirmantraṃ smarati. अयं कविर्मन्त्रं स्मरति | अनेन कविना मन्त्रः स्मृतः ।</p><p>8. iyaṃ devī kṣatriyā rakṣati. इयं देवी क्त्रिया रक्षति | अनया देव्या क्षत्रिया रक्षिताः ।</p><p>9. kṣatriyā viṣṇuṃ yajante. क्षत्रिया विष्णुं यजन्ते | (2 Möglichkeiten) क्षत्रियैर्विष्णुरिष्टः । क्षत्रियाभिर्विष्णुरिष्टः ।</p><p>10. brāhmaṇo &#39;gniṃ karoti. ब्राह्मणो ऽग्निं करोति | ब्राह्मणेनाग्निः कृतः ।</p><p>11. vaiśyā imaṃ grāmaṃ gacchanti. वैश्या इमं ग्रामं गच्छन्ति | वैश्या इमं ग्रामं गताः ।</p><p>12. ete gurūṃstu śṛṇvanti. एते गुरूंस्तु शृण्वन्ति | एतैर्गुरवस्तु श्रुताः ।</p><p>13. sādhuḥ svargamāpnoti. साधुः स्वर्गमाप्नोति | साधुना स्वर्ग आप्ताः ।</p><p>14. brāhmāṇāḥ somaṃ sunvanti. ब्राह्मणाः सोमं सुन्वन्ति | ब्राह्मणैः सोमः सुतः ।</p><p>15. paśūṃllabhate. पशूल्ंलभते | पशवो लब्धाः ।</p><p>16. ke yodhāḥ kṣatriyaiḥ saha yudhyante. के योधाः क्षत्रियैः सह युध्यन्ते | कैर्योधैः क्षत्रियैः सह युद्धम् ।</p><p><img src="'+r+'" alt=""><br> Abb.: ब्राह्मणो ऽग्निं करोति |<br> Modernes Feuerbohren für ein Opfer, Shiva ashram, Kothavala, Ganeshpuri, 80 km von Mumbai (मुंबई) entfernt<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/466067768/in/set-72157600010457470/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/466067768/in/set-72157600010457470/</a>. -- Zugriff am 2008-12-06. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Comons Lizenz (Namensnennung, keine kommerzielle Nutzung, Share alike)]</p>',28)])])}const c=i(l,[["render",p]]);export{m as __pageData,c as default};
